## Code Example

```javascript
class SLOMonitor {
  constructor(targetAvailability, warningThreshold = 0.7) {
    this.target = targetAvailability;
    this.warningThreshold = warningThreshold;
    this.errorBudget = 1 - targetAvailability;
    this.burnRate = 0;
  }

  recordRequest(success, latencyMs) {
    this.totalRequests++;
    if (!success) this.errors++;
    this.totalLatency += latencyMs;
    this.updateBurnRate();
  }

  updateBurnRate() {
    const elapsed = (Date.now() - this.windowStart) / 3600000;
    const errorRate = this.errors / this.totalRequests;
    this.burnRate = errorRate / (this.errorBudget * elapsed);
  }

  canaryPass(latencyP95, errorRate) {
    return latencyP95 < 300 && errorRate < this.errorBudget;
  }

  shouldAlert() {
    return this.burnRate > this.warningThreshold;
  }

  getStatus() {
    return {
      availability: 1 - (this.errors / this.totalRequests),
      burnRate: this.burnRate,
      alert: this.shouldAlert(),
      rolloutSafe: this.burnRate < 1.0
    };
  }
}

const featureGate = {
  rollout: (percentage, errorBudgetStatus) => {
    if (!errorBudgetStatus.rolloutSafe) return 'BLOCKED';
    return Math.random() * 100 < percentage ? 'ENABLED' : 'DISABLED';
  }
};
```

