// Simple data contract validation
function validateRecord(record, schema) {
  const errors = [];

  for (const [field, fieldSchema] of Object.entries(schema)) {
    const value = record[field];

    if (fieldSchema.required && value === undefined) {
      errors.push(`Missing required field: ${field}`);
      continue;
    }

    if (value !== undefined) {
      const actualType = typeof value;
      const expectedType = fieldSchema.type;

      if (actualType !== expectedType) {
        errors.push(`Field '${field}' expected type ${expectedType}, got ${actualType}`);
      }
    }
  }

  return {
    valid: errors.length === 0,
    errors
  };
}

// Example usage
const userEventSchema = {
  userId: { type: 'string', required: true },
  eventType: { type: 'string', required: true },
  timestamp: { type: 'number', required: true },
  metadata: { type: 'object', required: false }
};

const result = validateRecord({ userId: '123', eventType: 'click' }, userEventSchema);
console.log(result);
// { valid: false, errors: ['Missing required field: timestamp'] }
```

